function tutorReply(t){
  const q=t.toLowerCase().replace(/[?.,-]/g," "),career=FINANCE_CAREERS.find(c=>q.includes(c.name.toLowerCase())||q.includes(c.name.toLowerCase().replace(/\s*\(.+?\)/,""))),careerTopic=["career","job","salary","certification","university","college","skills","responsibilities","pathway"].some(x=>q.includes(x));
  if(career)return `<strong>${career.name}</strong><br><br><strong>Career overview:</strong> ${career.definition}<br><br><strong>What the work involves:</strong> ${career.tasks.join("; ")}.<br><br><strong>Salary:</strong> In India, typical ranges progress from ${career.india.join(" to ")}. In the United States, ranges progress from ${career.usa.join(" to ")}. Actual compensation varies by location, firm, and performance.<br><br><strong>Relevant skills:</strong> ${career.skills.join(", ")}.<br><br><strong>Education and progression:</strong> ${career.roadmap.join(" → ")}. Helpful majors include ${career.majors.join(", ")}, while useful certifications include ${career.certifications.join(", ")}.<br><br><strong>Benefits:</strong> Strong learning, meaningful business exposure, and attractive long-term career opportunities.<br><br><strong>Challenges:</strong> Difficulty is ${career.difficulty}/10, so students should expect competition, demanding skill development, and responsibility.<br><br><strong>Personality match:</strong> This career often suits students who ${career.fit.join(", ").toLowerCase()}.`;
  const keys=Object.keys(FINANCE_KNOWLEDGE).sort((a,b)=>b.length-a.length),key=keys.find(k=>q.includes(k));
  if(key){const [area,definition,example]=FINANCE_KNOWLEDGE[key],related=FINANCE_CAREERS.filter(c=>c.skills.some(s=>s.toLowerCase().includes(key))||c.definition.toLowerCase().includes(key)).slice(0,3).map(c=>c.name);return `<strong>${key.replace(/\b\w/g,c=>c.toUpperCase())}</strong> · ${area}<br><br><strong>Clear explanation:</strong> ${definition}<br><br><strong>Real-world example:</strong> ${example}<br><br><strong>Why it matters:</strong> This helps students understand how money, value, risk, ownership, trade, or business decisions actually work instead of memorizing definitions.<br><br><strong>Benefits and uses:</strong> Knowing this concept improves decision-making, helps compare choices, and makes business or financial consequences easier to see.<br><br><strong>Challenges:</strong> The concept must be applied with accurate information and context. In real life, timing, incentives, rules, competition, and human behavior can change the answer.${related.length?`<br><br><strong>Career opportunities:</strong> This knowledge is especially useful in ${related.join(", ")}.`:""}<br><br><strong>Try this:</strong> Create a tiny example with numbers. If the logic still works with numbers, you probably understand the concept.`;
  }
  if(careerTopic)return `<strong>Finance career guidance</strong><br><br>FinTeen Career Explorer covers ${FINANCE_CAREERS.map(c=>c.name).join(", ")}.<br><br>I can explain responsibilities, salaries, difficulty, skills, certifications, college majors, university pathways, internships, personality fit, and career progression. For example, if you ask about Private Equity, I can explain why many people first work in investment banking, what LBO analysis means, and what skills make someone competitive.`;
  const stop=new Set(["what","why","how","does","is","are","the","a","an","of","in","to","and","for","explain","tell","about","me"]),terms=q.split(/\s+/).filter(x=>x.length>3&&!stop.has(x)),paragraphs=[...LESSON_MARKDOWN,...PERSONAL_FINANCE_MARKDOWN,...INVESTING_MARKDOWN,...BUSINESS_MARKDOWN,...ACCOUNTING_MARKDOWN,...ADVANCED_FINANCE_MARKDOWN].flatMap(doc=>doc.split(/\n\n+/).map(p=>({p,score:terms.reduce((n,w)=>n+(p.toLowerCase().includes(w)?1:0),0)}))).filter(x=>x.score>0).sort((a,b)=>b.score-a.score);
  if(paragraphs[0]?.score>=Math.max(1,Math.min(2,terms.length))){const best=paragraphs.slice(0,4).map(x=>x.p.replace(/^#+\s*/,"").replace(/\*\*/g,"")).join("<br><br>");return `<strong>Explanation from the FinTeen lesson library:</strong><br><br>${best}<br><br><strong>Why it matters:</strong> This concept affects how people, businesses, or markets make decisions and manage risk.<br><br><strong>Practical application:</strong> Compare the choices available, calculate the financial effect, and identify the trade-offs before deciding.<br><br><strong>Critical-thinking check:</strong> What could go wrong, and what information would improve the decision?`;
  }
  const financeWords=["finance","financial","account","econom","business","bank","invest","money","market","company","corporate","fund","capital","cash","credit","debit","loan","interest","wealth","currency","payment","trade","tax","insurance","entrepreneur","profit","cost","price","income","expense","saving","portfolio","audit","commerce","budget","spending","goal","startup","marketing","revenue","career","salary","supply","demand","inventory","logistics","procurement","invoice","gst","tariff","subsidy","retail","wholesale","ecommerce","governance","compliance","risk","valuation","equity","liability","asset"];
  if(!financeWords.some(x=>q.includes(x)))return "Sorry, but your question is not related to finance, commerce, business, accounting, economics, banking, investing, or finance careers.";
  return `<strong>Let’s break this down like a finance problem.</strong><br><br><strong>1. Define the idea:</strong> First ask what is moving: money, goods, ownership, risk, information, or value.<br><br><strong>2. Identify the people involved:</strong> Most commerce and finance questions involve customers, businesses, banks, investors, governments, suppliers, or employees.<br><br><strong>3. Look for the numbers:</strong> Revenue, cost, price, profit, cash flow, interest, tax, inventory, or return usually reveal what is really happening.<br><br><strong>4. Real-world example:</strong> If a business sells products online, it must manage demand, inventory, payment collection, delivery, tax, customer service, and profit margins. One weak part can affect the whole business.<br><br><strong>5. Benefits and challenges:</strong> Good financial thinking creates better choices and stronger businesses, but uncertainty, incomplete information, competition, regulation, and human behavior make decisions harder.<br><br>Ask the question with one specific term, company situation, career, or calculation, and I’ll give you a full structured explanation.`;
}
function createChatScroller(container){
  let auto=true, scheduled=false;
  const nearBottom=()=>container.scrollHeight-container.scrollTop-container.clientHeight<90;
  const scroll=()=>{if(!auto||scheduled)return;scheduled=true;requestAnimationFrame(()=>{container.scrollTo({top:container.scrollHeight,behavior:"smooth"});scheduled=false})};
  container.addEventListener("scroll",()=>{auto=nearBottom()},{passive:true});
  return {scroll,enable(){auto=true;scroll()},finish(){if(nearBottom())scroll()}};
}
function typeTutorReply(target,html,scroller){
  const source=document.createElement("div");
  source.innerHTML=html;
  target.innerHTML="";
  const typeText=(text,parent,done)=>{let i=0,node=document.createTextNode("");parent.appendChild(node);const tick=()=>{node.textContent+=text.slice(i,i+7);i+=7;scroller?.scroll();if(i<text.length)setTimeout(tick,9);else done()};tick()};
  const typeChildren=(nodes,parent,done)=>{let i=0;const next=()=>{if(i>=nodes.length){done();return}typeNode(nodes[i++],parent,next)};next()};
  const typeNode=(node,parent,done)=>{if(node.nodeType===Node.TEXT_NODE){typeText(node.textContent,parent,done);return}if(node.nodeType===Node.ELEMENT_NODE){const clone=node.cloneNode(false);parent.appendChild(clone);scroller?.scroll();typeChildren([...node.childNodes],clone,done);return}done()};
  typeChildren([...source.childNodes],target,()=>{target.classList.remove("typing");scroller?.finish()});
}
function quizMessage(percent){return percent>=90?"Excellent work":percent>=70?"Strong understanding":percent>=50?"Good start, review the lesson":"Review the lesson and try again"}
function renderQuiz(){if(lastQuizResult){const p=Math.round(lastQuizResult.score/lastQuizResult.total*100);return `<div class="quiz-wrap result-wrap">${pageHead("Quiz complete",lastQuizResult.lesson,"Your quiz was saved and your progress has been updated.")}<section class="card quiz-result-card"><div class="result-score"><span>Score</span><strong>${lastQuizResult.score}/${lastQuizResult.total}</strong><em>${p}%</em></div><h2>${quizMessage(p)}</h2><p>${p>=70?"You are building strong financial understanding. Keep going through the next lessons and quizzes.":"Review the lesson once more, focus on the explanations, and try another quiz when ready."}</p><div class="result-actions"><button class="button secondary" data-module="${activeModule}">Back to lessons</button><button class="button primary" data-view="dashboard">Go to dashboard →</button></div></section></div>`}const item=currentQuiz()[quizIndex],doc=getActiveDoc(),percent=(quizIndex+1)/12*100;return `<div class="quiz-wrap quiz-fade">${pageHead(item.level,doc?.title||"Lesson quiz","12 unique questions based on this exact lesson.")}<div class="quiz-progress"><div class="progress-track"><div class="progress-fill" style="width:${percent}%"></div></div><span>Question ${quizIndex+1} of 12</span></div><section class="card quiz-card" style="--quiz-step:${quizIndex}"><div class="quiz-card-top"><span class="question-tag">${item.level.charAt(0)+item.level.slice(1).toLowerCase()}</span><span class="quiz-number">Question ${quizIndex+1}/12</span></div><h2>${item.q}</h2><div class="answer-list">${item.options.map((x,i)=>`<button class="answer" data-answer="${i}"><b>${String.fromCharCode(65+i)}</b><span>${x}</span></button>`).join("")}</div><div class="quiz-feedback hidden" id="quiz-feedback"></div><button class="button primary hidden" id="next-question" style="margin-top:16px">${quizIndex===11?"See results":"Next question"} →</button></section></div>`}
function revealQuizNextButton(){const next=document.getElementById("next-question"),wrap=document.querySelector(".quiz-wrap");if(!next)return;next.classList.remove("hidden");const scrollToQuizResult=()=>{const top=wrap?.getBoundingClientRect().top??0,target=window.scrollY+top-24;window.scrollTo({top:Math.max(0,target),behavior:"smooth"})};requestAnimationFrame(()=>{scrollToQuizResult();setTimeout(scrollToQuizResult,220)})}
function animateView(){container.classList.remove("view-enter");void container.offsetWidth;container.classList.add("view-enter");container.querySelectorAll(".card,.lesson-row,.module-card,.career-card,.answer,.prompt,.summary-cell,.allocation-summary > div").forEach((el,i)=>{el.style.setProperty("--stagger",`${Math.min(i,10)*100}ms`);el.classList.remove("stagger-in");void el.offsetWidth;el.classList.add("stagger-in")})}
function navigate(view){currentView=view;title.textContent=({dashboard:"Overview",learn:"Learning Center",simulator:"Budget Lab",savings:"Savings Analyzer",tutor:"AI Tutor",careers:"Career Explorer",quiz:"Quiz"})[view];document.querySelectorAll(".nav-item").forEach(x=>x.classList.toggle("active",x.dataset.view===view));container.innerHTML=({dashboard:renderDashboard,learn:renderLearn,simulator:renderSimulator,savings:renderSavingsAnalyzer,tutor:renderTutor,careers:renderCareers,quiz:renderQuiz})[view]();bind();animateView();window.scrollTo({top:0,behavior:"smooth"})}
function bind(){
  document.querySelectorAll("[data-view]").forEach(x=>x.onclick=e=>{e.preventDefault();activeModule=activeLesson=activeCareer=null;navigate(x.dataset.view);document.querySelector(".sidebar").classList.remove("open")});
  document.querySelectorAll("[data-career]").forEach(x=>x.onclick=()=>{activeCareer=+x.dataset.career;navigate("careers")});
  document.querySelectorAll("[data-career-card]").forEach(x=>{x.onclick=e=>{if(e.target.closest("button"))return;activeCareer=+x.dataset.careerCard;navigate("careers")};x.onkeydown=e=>{if((e.key==="Enter"||e.key===" ")&&!e.target.closest("button")){e.preventDefault();activeCareer=+x.dataset.careerCard;navigate("careers")}}});
  document.getElementById("back-careers")?.addEventListener("click",()=>{activeCareer=null;navigate("careers")});
  document.querySelectorAll("[data-module]").forEach(x=>x.onclick=()=>{activeModule=+x.dataset.module;activeLesson=null;navigate("learn")});
  document.querySelectorAll("[data-lesson]").forEach(x=>x.onclick=()=>{activeLesson=+x.dataset.lesson;navigate("learn")});
  document.querySelectorAll("[data-quiz]").forEach(x=>x.onclick=()=>{activeLesson=+x.dataset.quiz;quizIndex=quizScore=0;lastQuizResult=null;navigate("quiz")});
  document.querySelectorAll("[data-lesson-row]").forEach(x=>{x.onclick=e=>{if(e.target.closest("button"))return;activeLesson=+x.dataset.lessonRow;navigate("learn")};x.onkeydown=e=>{if((e.key==="Enter"||e.key===" ")&&!e.target.closest("button")){e.preventDefault();activeLesson=+x.dataset.lessonRow;navigate("learn")}}});
  document.getElementById("back-modules")?.addEventListener("click",()=>{activeModule=null;navigate("learn")});
  ["back-lessons","back-lessons-2"].forEach(id=>document.getElementById(id)?.addEventListener("click",()=>{activeLesson=null;navigate("learn")}));
  document.getElementById("complete-lesson")?.addEventListener("click",()=>{const id=`${activeModule}-${activeLesson}`;if(!state.completedLessons.includes(id)){state.completedLessons.push(id);save();syncUser()}navigate("learn")});
  document.querySelectorAll(".goal-pill").forEach(x=>x.onclick=()=>{document.querySelectorAll(".goal-pill").forEach(p=>p.classList.remove("active"));x.classList.add("active");document.querySelector(".custom-goal").classList.toggle("show",x.dataset.goal==="Custom Goal")});
  document.getElementById("run-sim")?.addEventListener("click",runSimulator);
  document.querySelectorAll(".allocation-slider").forEach(x=>x.oninput=e=>scheduleBudgetAllocation(e.target));
  document.getElementById("run-savings-analysis")?.addEventListener("click",updateSavingsAnalyzer);
  document.querySelectorAll(".savings-field,#savings-income,#savings-other-name").forEach(x=>x.oninput=e=>scheduleSavingsAnalyzer(e.target));
  document.getElementById("savings-modal-next")?.addEventListener("click",()=>{document.getElementById("savings-modal").innerHTML=`<div class="card coach-modal-card"><p class="eyebrow">Savings Analyzer</p><h2>How It Works</h2><p>1. Enter your income.<br>2. Enter how much you spent in each category.<br>3. FinTeen will calculate your spending percentages.<br>4. Receive a personalized financial analysis.<br>5. Learn where to improve your financial habits.</p><button class="button primary full" id="savings-modal-close">Continue</button></div>`;document.getElementById("savings-modal-close").onclick=()=>{smartSavingsTutorialShown=true;sessionStorage.setItem("smartSavingsTutorialShown","true");document.getElementById("savings-modal").remove()}});
  if(document.getElementById("savings-income"))updateSavingsDraft();
  document.querySelectorAll(".prompt").forEach(x=>x.onclick=()=>{document.getElementById("chat-text").value=x.textContent;document.getElementById("chat-form").requestSubmit()});
  document.getElementById("chat-form")?.addEventListener("submit",e=>{e.preventDefault();const i=document.getElementById("chat-text"),m=document.getElementById("messages"),question=i.value.trim();if(!question)return;const scroller=createChatScroller(m);m.insertAdjacentHTML("beforeend",`<div class="message user">${question}</div><div class="message typing"><span class="typing-dot"></span></div>`);const reply=m.querySelector(".message.typing:last-child");i.value="";scroller.enable();typeTutorReply(reply,tutorReply(question),scroller)});
  document.querySelectorAll("[data-answer]").forEach(x=>x.onclick=()=>{const chosen=+x.dataset.answer,item=currentQuiz()[quizIndex];if(chosen===item.answer)quizScore++;document.querySelectorAll(".answer").forEach((a,i)=>{a.disabled=true;if(i===chosen)a.classList.add("selected");if(i===item.answer)a.classList.add("correct")});if(chosen!==item.answer)x.classList.add("wrong");document.getElementById("quiz-feedback").innerHTML=`<strong>${chosen===item.answer?"Correct.":"Not quite."}</strong> ${item.why}`;document.getElementById("quiz-feedback").classList.remove("hidden");revealQuizNextButton(x)});
  document.getElementById("next-question")?.addEventListener("click",()=>{if(quizIndex<11){quizIndex++;navigate("quiz")}else{const doc=getActiveDoc();state.quizzes.push({lesson:`${activeModule}-${activeLesson}`,score:quizScore});lastQuizResult={score:quizScore,total:12,lesson:doc.title};save();syncUser();quizIndex=quizScore=0;navigate("quiz")}});
}
